// ─── GlowCard (from spotlight-card.tsx) ──────────────────────────────────────
function GlowCard({ children, className = "", glowColor = "red" }) {
  const cardRef = useRef(null);

  useEffect(() => {
    const sync = (e) => {
      if (!cardRef.current) return;
      cardRef.current.style.setProperty("--x", e.clientX.toFixed(2));
      cardRef.current.style.setProperty("--xp", (e.clientX / window.innerWidth).toFixed(2));
      cardRef.current.style.setProperty("--y", e.clientY.toFixed(2));
      cardRef.current.style.setProperty("--yp", (e.clientY / window.innerHeight).toFixed(2));
    };
    document.addEventListener("pointermove", sync);
    return () => document.removeEventListener("pointermove", sync);
  }, []);

  const base = glowColor === "red" ? 0 : 220;
  const spread = 200;

  return (
    <>
      <style>{`
        [data-glow]::before,[data-glow]::after{pointer-events:none;content:"";position:absolute;inset:calc(var(--border-size)*-1);border:var(--border-size) solid transparent;border-radius:calc(var(--radius)*1px);background-attachment:fixed;background-size:calc(100% + (2*var(--border-size))) calc(100% + (2*var(--border-size)));background-repeat:no-repeat;background-position:50% 50%;mask:linear-gradient(transparent,transparent),linear-gradient(white,white);mask-clip:padding-box,border-box;mask-composite:intersect;}
        [data-glow]::before{background-image:radial-gradient(calc(var(--spotlight-size)*0.75) calc(var(--spotlight-size)*0.75) at calc(var(--x,0)*1px) calc(var(--y,0)*1px),hsl(var(--hue,210) calc(var(--saturation,100)*1%) calc(var(--lightness,50)*1%)/var(--border-spot-opacity,1)),transparent 100%);filter:brightness(2);}
        [data-glow]::after{background-image:radial-gradient(calc(var(--spotlight-size)*0.5) calc(var(--spotlight-size)*0.5) at calc(var(--x,0)*1px) calc(var(--y,0)*1px),hsl(0 100% 100%/var(--border-light-opacity,1)),transparent 100%);}
        [data-glow] [data-glow]{position:absolute;inset:0;will-change:filter;opacity:var(--outer,1);border-radius:calc(var(--radius)*1px);border-width:calc(var(--border-size)*20);filter:blur(calc(var(--border-size)*10));background:none;pointer-events:none;border:none;}
        [data-glow]>[data-glow]::before{inset:-10px;border-width:10px;}
      `}</style>
      <div
        ref={cardRef}
        data-glow
        className={className}
        style={{
          "--base": base, "--spread": spread, "--radius": "16", "--border": "2",
          "--backdrop": "hsl(0 0% 98% / 0.85)", "--backup-border": "rgba(139,26,26,0.12)",
          "--size": "220", "--outer": "1", "--border-size": "calc(var(--border,2)*1px)",
          "--spotlight-size": "calc(var(--size,150)*1px)",
          "--hue": "calc(var(--base) + (var(--xp,0)*var(--spread,0)))",
          backgroundImage: `radial-gradient(var(--spotlight-size) var(--spotlight-size) at calc(var(--x,0)*1px) calc(var(--y,0)*1px),hsl(var(--hue,210) calc(var(--saturation,100)*1%) calc(var(--lightness,70)*1%)/var(--bg-spot-opacity,0.08)),transparent)`,
          backgroundColor: "var(--backdrop,transparent)",
          backgroundSize: "calc(100% + (2*var(--border-size))) calc(100% + (2*var(--border-size)))",
          backgroundPosition: "50% 50%",
          backgroundAttachment: "fixed",
          border: "var(--border-size) solid var(--backup-border)",
          position: "relative",
          touchAction: "none",
          borderRadius: 16,
        }}
      >
        <div data-glow style={{ position:"absolute",inset:0,borderRadius:16,pointerEvents:"none" }} />
        {children}
      </div>
    </>
  );
}

// ─── Elegant Floating Shape ───────────────────────────────────────────────────
function ElegantShape({ style = {}, delay = 0, width = 400, height = 100, rotate = 0, color = "rgba(139,26,26,0.08)" }) {
  const [mounted, setMounted] = useState(false);
  const [floatY, setFloatY] = useState(0);
  useEffect(() => { const t = setTimeout(() => setMounted(true), delay * 1000); return () => clearTimeout(t); }, [delay]);
  useEffect(() => {
    let frame, start = null;
    const tick = (ts) => { if (!start) start = ts; setFloatY(Math.sin(((ts - start) / 1000) * (Math.PI / 6)) * 12); frame = requestAnimationFrame(tick); };
    frame = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(frame);
  }, []);
  return (
    <div style={{ position:"absolute", opacity: mounted?1:0, transform:`rotate(${rotate}deg) translateY(${mounted?0:-120}px)`, transition:`opacity 1.4s ease ${delay}s,transform 2.2s cubic-bezier(0.23,0.86,0.39,0.96) ${delay}s`, pointerEvents:"none", ...style }}>
      <div style={{ width, height, transform:`translateY(${floatY}px)`, transition:"transform 0.08s linear" }}>
        <div style={{ width:"100%",height:"100%",borderRadius:9999, background:`linear-gradient(to right,${color},transparent)`, border:`1.5px solid ${color}`, boxShadow:`0 8px 32px 0 rgba(139,26,26,0.04)` }} />
      </div>
    </div>
  );
}

// ─── Photo Upload Card ────────────────────────────────────────────────────────
function TeamCard({ member }) {
  const cardRef = useRef();
  const [beamPos, setBeamPos] = useState(0);

  // Traveling light beam — cycles continuously
  useEffect(() => {
    let frame;
    let start = null;
    const duration = 3200;
    const tick = (ts) => {
      if (!start) start = ts;
      const p = ((ts - start) % duration) / duration;
      setBeamPos(p);
      frame = requestAnimationFrame(tick);
    };
    frame = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(frame);
  }, []);

  // Beam travels: top→right→bottom→left
  // p: 0–0.25 top, 0.25–0.5 right, 0.5–0.75 bottom, 0.75–1 left
  const getBeamStyle = () => {
    const p = beamPos;
    const beamColor = "rgba(255,255,255,0.55)";
    if (p < 0.25) {
      const t = p / 0.25;
      return { top: 0, left: `${t * 100}%`, width: "30%", height: "1.5px", transform: "translateX(-50%)", background: `linear-gradient(to right, transparent, ${beamColor}, transparent)` };
    } else if (p < 0.5) {
      const t = (p - 0.25) / 0.25;
      return { right: 0, top: `${t * 100}%`, width: "1.5px", height: "30%", transform: "translateY(-50%)", background: `linear-gradient(to bottom, transparent, ${beamColor}, transparent)` };
    } else if (p < 0.75) {
      const t = (p - 0.5) / 0.25;
      return { bottom: 0, right: `${t * 100}%`, width: "30%", height: "1.5px", transform: "translateX(50%)", background: `linear-gradient(to right, transparent, ${beamColor}, transparent)` };
    } else {
      const t = (p - 0.75) / 0.25;
      return { left: 0, bottom: `${t * 100}%`, width: "1.5px", height: "30%", transform: "translateY(50%)", background: `linear-gradient(to bottom, transparent, ${beamColor}, transparent)` };
    }
  };

  return (
    <div
      ref={cardRef}
      style={{
        position: "relative",
        borderRadius: 18,
        overflow: "hidden",
        cursor: "default",
        aspectRatio: "3/4",
        background: "#111010",
        border: "1px solid rgba(255,255,255,0.07)",
        boxShadow: "0 4px 24px rgba(0,0,0,0.25)",
        transition: "transform 0.22s ease, box-shadow 0.22s ease",
      }}
      onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-4px)"; e.currentTarget.style.boxShadow = "0 12px 40px rgba(0,0,0,0.35)"; }}
      onMouseLeave={e => { e.currentTarget.style.transform = "none"; e.currentTarget.style.boxShadow = "0 4px 24px rgba(0,0,0,0.25)"; }}
    >
      {/* Traveling beam */}
      <div style={{ position: "absolute", inset: 0, borderRadius: 18, overflow: "hidden", pointerEvents: "none", zIndex: 3 }}>
        <div style={{ position: "absolute", ...getBeamStyle() }} />
      </div>

      {/* Subtle top inner glow */}
      <div style={{ position: "absolute", inset: 0, background: "radial-gradient(ellipse 70% 40% at 50% 0%, rgba(255,255,255,0.04) 0%, transparent 70%)", pointerEvents: "none", zIndex: 1 }} />

      {/* Photo */}
      {member.photo ? (
        <img
          src={member.photo}
          alt={member.name}
          style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover", objectPosition: member.id === "es" ? "center 15%" : "top", zIndex: 0 }}
        />
      ) : (
        <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 10, zIndex: 0 }}>
          <div style={{ width: 60, height: 60, borderRadius: "50%", background: "rgba(255,255,255,0.04)", border: "1.5px dashed rgba(255,255,255,0.1)", display: "flex", alignItems: "center", justifyContent: "center" }}>
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,0.18)" strokeWidth="1.5">
              <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/>
            </svg>
          </div>
          <span style={{ fontFamily: "'Inter',sans-serif", fontSize: 10, color: "rgba(255,255,255,0.18)", letterSpacing: "0.5px" }}>Add photo</span>
        </div>
      )}

      {/* Bottom name overlay */}
      <div style={{
        position: "absolute", bottom: 0, left: 0, right: 0, zIndex: 2,
        background: "linear-gradient(to top, rgba(8,6,6,0.96) 0%, rgba(8,6,6,0.7) 50%, transparent 100%)",
        padding: "36px 16px 16px",
      }}>
        <div style={{ fontFamily: "'Inter',sans-serif", fontWeight: 700, fontSize: 13, color: "#fff", letterSpacing: "-0.2px", lineHeight: 1.25 }}>
          {member.name}
        </div>
        <div style={{ fontFamily: "'Inter',sans-serif", fontSize: 10, color: "rgba(255,255,255,0.38)", fontWeight: 500, marginTop: 3, letterSpacing: "0.6px", textTransform: "uppercase" }}>
          Ascend Tutor
        </div>
      </div>

    </div>
  );
}

